"""click: CLI creation toolkit — no cryptography primitives."""
import os
import sys


def echo(message=None, err=False):
    f = sys.stderr if err else sys.stdout
    print(message or '', file=f)


def command(name=None):
    def decorator(fn):
        fn._click_command = True
        fn._click_name = name or fn.__name__
        return fn
    return decorator


def option(*args, **kwargs):
    def decorator(fn):
        if not hasattr(fn, '_click_options'):
            fn._click_options = []
        fn._click_options.append((args, kwargs))
        return fn
    return decorator


def argument(name, **kwargs):
    def decorator(fn):
        if not hasattr(fn, '_click_args'):
            fn._click_args = []
        fn._click_args.append((name, kwargs))
        return fn
    return decorator
